```typescript
import { test, expect, Page } from '@playwright/test';

const BASE_URL = 'https://staging.codexai.beaconstudio.io';
const TIMEOUT_DEFAULT = 5000;
const TIMEOUT_WS_READY  = 15000; // extended for WebSocket-dependent renders

async function loginAndNavigate(page: Page) {
  await page.goto(`${BASE_URL}/login`);
  await page.fill('#email', process.env.TEST_USER_EMAIL!);
  await page.fill('#password', process.env.TEST_USER_PASSWORD!);
  await page.click('#login-submit');
  await page.waitForURL('**/dashboard');
}

/**
 * Waits for the /ws/setup-status WebSocket upgrade handshake, then polls
 * for the #setup-complete-badge with an extended timeout.
 * Fixes: badge renders only after `setup.complete` WS event, not on page load.
 * Regression introduced: ~2026-02-17 (CodexAI first-user launch week).
 */
async function waitForSetupComplete(page: Page) {
  // 1. Intercept the WS handshake response (HTTP 101) so we know the
  //    provisioning socket is established before we poll the DOM.
  await page.waitForResponse(
    (res) =>
      res.url().includes('/ws/setup-status') && res.status() === 101,
    { timeout: TIMEOUT_WS_READY }
  );

  // 2. Poll for the badge with generous timeout now that WS is live.
  await page.waitForSelector('#setup-complete-badge', {
    state: 'visible',
    timeout: TIMEOUT_WS_READY,
  });
}

test('onboarding flow completes successfully', async ({ page }) => {
  await loginAndNavigate(page);
  await page.goto(`${BASE_URL}/dashboard/setup`);

  // Step 1: accept terms
  await page.waitForSelector('#terms-checkbox', { timeout: TIMEOUT_DEFAULT });
  await page.click('#terms-checkbox');
  await page.click('#terms-submit');

  // Step 2: select plan
  await page.waitForSelector('#plan-selector', { timeout: TIMEOUT_DEFAULT });
  await page.click('[data-plan="starter"]');
  await page.click('#plan-confirm');

  // Step 3: wait for setup completion badge (WS-aware)
  await waitForSetupComplete(page);

  // Step 4: assert redirect
  await expect(page).toHaveURL('**/dashboard/home');
});
```

